#include<cstdio>
#include<cmath>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e5+10,INF=0x3f3f3f3f;struct N1{int l,r,t,k,idx;}q[N];struct N2{int p,u,v;}t[N];
int n,Q,T,a[N],A[N],c[N],cc[N],pl[N],pr[N],ccc[N],loc[N],ql[N],qr[N],blk,ans[N],L,R,Tm,Bm,Bf;
inline void Ins(int c){++cc[c];++ccc[loc[c]];} inline void Del(int c){--cc[c];--ccc[loc[c]];}
inline void ins(int v){Del(c[v]);Ins(++c[v]);} inline void del(int v){Del(c[v]);Ins(--c[v]);}
inline void tmAdd(){++Tm;int p=t[Tm].p,v=t[Tm].v;if(L<=p&&p<=R)del(a[p]),ins(v);a[p]=v;}
inline void tmMns(){int p=t[Tm].p,u=t[Tm].u;--Tm;if(L<=p&&p<=R)del(a[p]),ins(u);a[p]=u;}
inline void Init()
{
	rep(1,n,i)loc[i]=(i-1)/Bf+1;blk=loc[n];
	rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*Bf;qr[blk]=n;
}
int p,g[N],s[N];inline int qry(const int &k)
{
	p=0;rep(1,blk,B)if(ccc[B]){rep(ql[B],qr[B],i)if(cc[i])g[++p]=i;}
	int r=0,sz=0;while(sz<k&&r<p)sz+=cc[g[++r]];if(sz<k)return -1;int res=g[r]-g[1];
	rep(2,p,l)
	{
		sz-=cc[g[l-1]];while(r<p&&sz<k){sz+=cc[g[++r]];}
		if(sz>=k)res=min(res,g[r]-g[l]);else break;
	}
	return res;
}
int main()
{
	n=read();int nQ=read();Bf=pow(n,0.33333);Bm=pow(n,0.66666);
	rep(1,n,i)a[i]=A[i]=read(),loc[i]=(i-1)/Bm;
	while(nQ--)
	{
		if(read()==1){++Q;q[Q].l=read();q[Q].r=read();q[Q].k=read();q[Q].t=T;q[Q].idx=Q;}
		else {int p=read(),v=read();t[++T]=(N2){p,A[p],v};A[p]=v;}
	}
	std::sort(q+1,q+Q+1,[&](const N1&x,const N1&y){return loc[x.l]==loc[y.l]?(loc[x.r]==loc[y.r]?(x.t<y.t):(loc[x.l]&1?x.r>y.r:x.r<y.r)):x.l<y.l;});
	Init();L=q[1].l;R=L-1;Tm=0;rep(1,Q,i)
	{
		while(R<q[i].r)ins(a[++R]);while(L>q[i].l)ins(a[--L]);
		while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		while(Tm<q[i].t)tmAdd();while(Tm>q[i].t)tmMns();ans[q[i].idx]=qry(q[i].k);
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
